/**
 * SpecSetupHandler - 管理 Spec 环境的初始化
 * 负责检测和执行 OpenSpec / SpecKit 的初始化步骤
 *
 * OpenSpec 流程 (2 步):
 *   1. CLI 检测/安装 - openspec --version 检测，失败时检查 Node.js 作为前置条件
 *   2. 目录初始化 - openspec init
 *
 * SpecKit 流程 (2 步):
 *   1. CLI 检测/安装 - specify version 检测，失败时检查 uv 作为前置条件
 *   2. 目录初始化 - specify init
 *
 * OpenSpec 升级流程 (3 步):
 *   1. 版本检测 - 检测是否为 0.23
 *   2. CLI 升级 - npm install 1.x
 *   3. 文档迁移 - openspec update --force
 */
import * as vscode from 'vscode';
import {
  SpecSetupStatus,
  SpecSetupStep,
  SpecSetupStepId,
  SpecSetupStepStatus,
  SpecSetupErrorCode,
  OpenSpecSetupStatus,
  OpenSpecSetupSteps,
  OpenSpecUpgradeStatus,
  SpecKitSetupStatus,
} from './types';
import { printLog } from '../logHandler/logHandler';
import getErrorMessage from '../../utils/getErrorMessage';
import { runTerminalCommand } from '../../utils/runTerminalCommand';

/** Node.js 最低版本要求 */
const MIN_NODE_VERSION = '20.19.0';

/**
 * 版本号匹配模式
 * 支持格式: 1.0.0, v1.0.0, 0.23.0, 1.2.3-beta, 1.2.3-rc.1 等
 */
const VERSION_PATTERN = /v?\d+\.\d+\.\d+(-[\w.]+)?/;

/**
 * 从输出中提取版本号
 * @param output 命令输出
 * @returns 版本号字符串，如果未找到则返回 undefined
 */
function extractVersion(output: string): string | undefined {
  const match = output.match(VERSION_PATTERN);
  return match ? match[0] : undefined;
}

/**
 * 比较两个版本号
 * @returns 负数表示 v1 < v2，0 表示相等，正数表示 v1 > v2
 */
function compareVersions(v1: string, v2: string): number {
  const parts1 = v1.split('.').map(Number);
  const parts2 = v2.split('.').map(Number);
  const len = Math.max(parts1.length, parts2.length);

  for (let i = 0; i < len; i++) {
    const p1 = parts1[i] || 0;
    const p2 = parts2[i] || 0;
    if (p1 !== p2) {
      return p1 - p2;
    }
  }
  return 0;
}

/**
 * 检查安装的版本是否匹配请求的版本
 * @param installedVersion 已安装的版本号 (如 "0.23.0", "1.1.1")
 * @param requestedVersion 请求的版本 ('0.23' 或 '1.x')
 * @returns 是否匹配
 */
function isVersionMatch(installedVersion: string, requestedVersion: '0.23' | '1.x'): boolean {
  // 移除可能的 v 前缀
  const cleanVersion = installedVersion.replace(/^v/, '');
  const majorVersion = cleanVersion.split('.')[0];

  if (requestedVersion === '0.23') {
    // 0.23 版本：主版本号必须是 0
    return majorVersion === '0';
  } else {
    // 1.x 版本：主版本号必须是 1
    return majorVersion === '1';
  }
}

/**
 * 创建默认的步骤状态
 */
function createStep(
  id: SpecSetupStepId,
  status: SpecSetupStepStatus = SpecSetupStepStatus.Pending,
  errorMessage?: string
): SpecSetupStep {
  return { id, status, errorMessage };
}

/**
 * 创建默认的 OpenSpec Setup 状态 (2 步)
 */
function createDefaultOpenSpecStatus(): OpenSpecSetupStatus {
  return {
    openspecCli: createStep(SpecSetupStepId.OpenspecCli),
    openspecInit: createStep(SpecSetupStepId.OpenspecInit),
  };
}

/**
 * 创建默认的 SpecKit Setup 状态 (2 步)
 */
function createDefaultSpecKitStatus(): SpecKitSetupStatus {
  return {
    specifyCli: createStep(SpecSetupStepId.SpecifyCli),
    speckitInit: createStep(SpecSetupStepId.SpeckitInit),
  };
}

/**
 * 创建默认的 OpenSpec 升级状态 (3 步)
 */
function createDefaultUpgradeStatus(): OpenSpecUpgradeStatus {
  return {
    versionCheck: createStep(SpecSetupStepId.UpgradeVersionCheck),
    cliUpgrade: createStep(SpecSetupStepId.UpgradeCli),
    migrateDocs: createStep(SpecSetupStepId.UpgradeMigrateDocs),
  };
}

/**
 * SpecSetupHandler 类
 */
export class SpecSetupHandler {
  private setupStatus: SpecSetupStatus;
  private workspaceRoot: string;
  private onStatusChange?: () => void;

  constructor(workspaceRoot: string, onStatusChange?: () => void) {
    this.workspaceRoot = workspaceRoot;
    this.onStatusChange = onStatusChange;
    this.setupStatus = {
      openspec: createDefaultOpenSpecStatus(),
      speckit: createDefaultSpecKitStatus(),
    };
  }

  /**
   * 获取当前的 setup 状态
   */
  public getSetupStatus(): SpecSetupStatus {
    return this.setupStatus;
  }

  /**
   * 通知状态变更 (立即触发)
   */
  private notifyStatusChange(): void {
    if (this.onStatusChange) {
      this.onStatusChange();
    }
  }

  /**
   * 更新 OpenSpec 步骤状态
   * @param stepKey 步骤标识
   * @param status 新状态
   * @param options 可选参数
   * @param options.errorCode 错误码 (仅 failed 状态)
   * @param options.errorMessage 错误信息 (仅 failed 状态)
   * @param options.progressMessage 进度消息 (仅 running 状态)
   * @param options.silent 是否静默更新（不触发通知）
   * @returns 状态是否发生变化
   */
  private updateOpenSpecStep(
    stepKey: keyof OpenSpecSetupSteps,
    status: SpecSetupStepStatus,
    options: {
      errorCode?: SpecSetupErrorCode;
      errorMessage?: string;
      progressMessage?: string;
      silent?: boolean;
    } = {}
  ): boolean {
    const { errorCode, errorMessage, progressMessage, silent = false } = options;
    const oldStatus = this.setupStatus.openspec[stepKey].status;
    const oldProgressMessage = this.setupStatus.openspec[stepKey].progressMessage;
    const statusChanged = oldStatus !== status;
    const progressChanged = oldProgressMessage !== progressMessage;

    this.setupStatus.openspec[stepKey] = {
      ...this.setupStatus.openspec[stepKey],
      status,
      errorCode,
      errorMessage,
      progressMessage,
    };

    // 状态变化或进度消息变化时都需要通知
    if ((statusChanged || progressChanged) && !silent) {
      this.notifyStatusChange();
    }
    return statusChanged;
  }

  /**
   * 更新 SpecKit 步骤状态
   * @param stepKey 步骤标识
   * @param status 新状态
   * @param options 可选参数
   * @param options.errorCode 错误码 (仅 failed 状态)
   * @param options.errorMessage 错误信息 (仅 failed 状态)
   * @param options.progressMessage 进度消息 (仅 running 状态)
   * @param options.silent 是否静默更新（不触发通知）
   * @returns 状态是否发生变化
   */
  private updateSpecKitStep(
    stepKey: keyof SpecKitSetupStatus,
    status: SpecSetupStepStatus,
    options: {
      errorCode?: SpecSetupErrorCode;
      errorMessage?: string;
      progressMessage?: string;
      silent?: boolean;
    } = {}
  ): boolean {
    const { errorCode, errorMessage, progressMessage, silent = false } = options;
    const oldStatus = this.setupStatus.speckit[stepKey].status;
    const oldProgressMessage = this.setupStatus.speckit[stepKey].progressMessage;
    const statusChanged = oldStatus !== status;
    const progressChanged = oldProgressMessage !== progressMessage;

    this.setupStatus.speckit[stepKey] = {
      ...this.setupStatus.speckit[stepKey],
      status,
      errorCode,
      errorMessage,
      progressMessage,
    };

    // 状态变化或进度消息变化时都需要通知
    if ((statusChanged || progressChanged) && !silent) {
      this.notifyStatusChange();
    }
    return statusChanged;
  }

  /**
   * 更新升级步骤状态
   * @param stepKey 步骤标识
   * @param status 新状态
   * @param options 可选参数
   */
  private updateOpenSpecUpgradeStep(
    stepKey: 'versionCheck' | 'cliUpgrade' | 'migrateDocs',
    status: SpecSetupStepStatus,
    options: {
      errorCode?: SpecSetupErrorCode;
      errorMessage?: string;
      progressMessage?: string;
    } = {}
  ): void {
    if (!this.setupStatus.openspecUpgrade) {
      return;
    }

    const { errorCode, errorMessage, progressMessage } = options;
    this.setupStatus.openspecUpgrade[stepKey] = {
      ...this.setupStatus.openspecUpgrade[stepKey],
      status,
      errorCode,
      errorMessage,
      progressMessage,
    };
    this.notifyStatusChange();
  }

  // ==================== 前置条件检测 (内部使用) ====================

  /**
   * 检测 Node.js 版本是否满足要求
   * 如果命令执行失败或版本号格式不正确，都视为未安装
   * @returns { ok: boolean, errorCode?: SpecSetupErrorCode, errorMessage?: string }
   */
  private async checkNodeVersion(): Promise<{
    ok: boolean;
    errorCode?: SpecSetupErrorCode;
    errorMessage?: string;
  }> {
    try {
      const result = await runTerminalCommand('node --version', this.workspaceRoot, { timeout: 10000 });
      if (!result.success) {
        return {
          ok: false,
          errorCode: SpecSetupErrorCode.NODE_UNAVAILABLE,
          errorMessage: 'Node.js 检测超时或执行异常',
        };
      }

      // 解析版本号 (格式: v20.19.0)
      // 如果版本号格式不正确，视为未安装
      const version = extractVersion(result.output);
      if (!version) {
        printLog(`[SpecSetupHandler] Node.js 版本格式不正确，视为未安装: ${result.output}`);
        return {
          ok: false,
          errorCode: SpecSetupErrorCode.NODE_UNAVAILABLE,
          errorMessage: 'Node.js 未安装或版本格式无法识别',
        };
      }

      // 移除可能的 v 前缀进行比较
      const cleanVersion = version.replace(/^v/, '');
      if (compareVersions(cleanVersion, MIN_NODE_VERSION) < 0) {
        return {
          ok: false,
          errorCode: SpecSetupErrorCode.NODE_VERSION_INVALID,
          errorMessage: `Node.js 版本 ${cleanVersion} 不满足要求，需要 >= ${MIN_NODE_VERSION}`,
        };
      }

      printLog(`[SpecSetupHandler] Node.js 版本检测通过: ${cleanVersion}`);
      return { ok: true };
    } catch (err) {
      return {
        ok: false,
        errorCode: SpecSetupErrorCode.NODE_UNAVAILABLE,
        errorMessage: 'Node.js 检测超时或执行异常',
      };
    }
  }

  /**
   * 检测 uv 是否可用
   * @returns { ok: boolean, errorCode?: SpecSetupErrorCode, errorMessage?: string }
   */
  private async checkUv(): Promise<{
    ok: boolean;
    errorCode?: SpecSetupErrorCode;
    errorMessage?: string;
  }> {
    try {
      const result = await runTerminalCommand('uv --version', this.workspaceRoot, { timeout: 10000 });
      if (!result.success) {
        return {
          ok: false,
          errorCode: SpecSetupErrorCode.UV_UNAVAILABLE,
          errorMessage: 'uv 未安装',
        };
      }

      // 如果版本号格式不正确，视为未安装
      const version = extractVersion(result.output);
      if (!version) {
        printLog(`[SpecSetupHandler] uv 版本格式不正确，视为未安装: ${result.output}`);
        return {
          ok: false,
          errorCode: SpecSetupErrorCode.UV_UNAVAILABLE,
          errorMessage: 'uv 未安装或版本格式无法识别',
        };
      }

      printLog(`[SpecSetupHandler] uv 已安装: ${version}`);
      return { ok: true };
    } catch {
      return {
        ok: false,
        errorCode: SpecSetupErrorCode.UV_UNAVAILABLE,
        errorMessage: 'uv 未安装',
      };
    }
  }

  // ==================== CLI 检测方法 ====================

  /**
   * 检测 OpenSpec CLI 是否可用
   * 如果 CLI 不可用，会检查 Node.js 作为前置条件并返回相应错误码
   * @param silent 是否静默更新（不触发通知）
   * @returns { installed: boolean, version?: string } 是否已安装以及安装的版本号
   */
  public async checkOpenspecCli(silent = false): Promise<{ installed: boolean; version?: string }> {
    try {
      const result = await runTerminalCommand(
        'openspec --version',
        this.workspaceRoot,
        { timeout: 10000 }
      );
      if (result.success) {
        const version = extractVersion(result.output);
        if (version) {
          this.updateOpenSpecStep('openspecCli', SpecSetupStepStatus.Completed, { silent });
          this.setupStatus.openspec.cliVersion = version;
          printLog(`[SpecSetupHandler] OpenSpec CLI 已安装: ${version}`);
          return { installed: true, version };
        }
      }
    } catch {
      // CLI 不可用，继续检查前置条件
    }

    // CLI 不可用，检查 Node.js 作为前置条件
    const nodeCheck = await this.checkNodeVersion();
    if (!nodeCheck.ok) {
      // Node.js 有问题，将错误码和错误信息作为 CLI 步骤的错误
      this.updateOpenSpecStep(
        'openspecCli',
        SpecSetupStepStatus.Failed,
        {
          errorCode: nodeCheck.errorCode,
          errorMessage: nodeCheck.errorMessage,
          silent,
        }
      );
      return { installed: false };
    }

    // Node.js 正常但 CLI 未安装，标记为 Pending (可安装)
    this.updateOpenSpecStep('openspecCli', SpecSetupStepStatus.Pending, { silent });
    return { installed: false };
  }

  /**
   * 检测 Specify CLI 是否可用
   * 如果 CLI 不可用，会检查 uv 作为前置条件并返回相应错误码
   * @param silent 是否静默更新（不触发通知）
   */
  public async checkSpecifyCli(silent = false): Promise<boolean> {
    try {
      const result = await runTerminalCommand(
        'specify version',
        this.workspaceRoot,
        { timeout: 10000 }
      );
      if (result.success) {
        const version = extractVersion(result.output);
        if (version) {
          this.updateSpecKitStep('specifyCli', SpecSetupStepStatus.Completed, { silent });
          printLog(`[SpecSetupHandler] Specify CLI 已安装: ${version}`);
          return true;
        }
      }
    } catch {
      // CLI 不可用，继续检查前置条件
    }

    // CLI 不可用，检查 uv 作为前置条件
    const uvCheck = await this.checkUv();
    if (!uvCheck.ok) {
      // uv 有问题，将错误码和错误信息作为 CLI 步骤的错误
      this.updateSpecKitStep(
        'specifyCli',
        SpecSetupStepStatus.Failed,
        {
          errorCode: uvCheck.errorCode,
          errorMessage: uvCheck.errorMessage,
          silent,
        }
      );
      return false;
    }

    // uv 正常但 CLI 未安装，标记为 Pending (可安装)
    this.updateSpecKitStep('specifyCli', SpecSetupStepStatus.Pending, { silent });
    return false;
  }

  // ==================== 目录初始化检测方法 ====================

