  // ==================== 目录初始化方法 ====================

  /**
   * 初始化 OpenSpec 目录 (通过 VSCode Terminal)
   * 执行完成后通过 checkOpenspecInit 验证目录是否真正创建
   * @param requestedVersion 请求的版本 ('0.23' 或 '1.x')
   * @param installedVersion 已安装的版本号（如果有）
   */
  private async initOpenspec(
    requestedVersion: '0.23' | '1.x',
    installedVersion?: string
  ): Promise<boolean> {
    // 决定使用全局命令还是 npx
    // 0.23 版本不支持 --force 参数，仅 1.x+ 支持
    const forceFlag = requestedVersion === '1.x' ? ' --force' : '';
    let command: string;
    if (installedVersion && isVersionMatch(installedVersion, requestedVersion)) {
      // 版本匹配，使用全局命令
      command = `openspec init --tools none${forceFlag}`;
      printLog(`[SpecSetupHandler] 使用全局 OpenSpec CLI (${installedVersion})`);
    } else {
      // 版本不匹配或未安装，使用 npx 指定版本
      const packageName = requestedVersion === '0.23'
        ? '@fission-ai/openspec@0.23.0'
        : '@fission-ai/openspec@1';
      command = `npx -y ${packageName} init --tools none${forceFlag}`;
      printLog(`[SpecSetupHandler] 使用 npx 执行 ${packageName}`);
    }

    // 发送进度消息：正在初始化
    this.updateOpenSpecStep('openspecInit', SpecSetupStepStatus.Running, {
      progressMessage: '正在初始化 OpenSpec 目录...',
    });
    printLog(`[SpecSetupHandler] 开始初始化 OpenSpec (via Terminal): ${command}`);

    try {
      const result = await runTerminalCommand(
        command,
        this.workspaceRoot,
        { timeout: 300000 } // 增加超时时间到 5 分钟
      );

      if (!result.success) {
        this.updateOpenSpecStep(
          'openspecInit',
          SpecSetupStepStatus.Failed,
          {
            errorCode: SpecSetupErrorCode.OPENSPEC_INIT_FAILED,
            errorMessage: `初始化 OpenSpec 失败: ${result.error || '未知错误'}`,
          }
        );
        return false;
      }

      // 发送进度消息：正在验证
      this.updateOpenSpecStep('openspecInit', SpecSetupStepStatus.Running, {
        progressMessage: '正在验证目录...',
      });

      // 命令执行成功后，通过检测目录来最终确认初始化是否成功
      const initSuccess = await this.checkOpenspecInit(true);
      if (!initSuccess) {
        this.updateOpenSpecStep(
          'openspecInit',
          SpecSetupStepStatus.Failed,
          {
            errorCode: SpecSetupErrorCode.OPENSPEC_INIT_FAILED,
            errorMessage: '初始化命令执行成功，但 openspec 目录未创建',
          }
        );
        return false;
      }

      printLog('[SpecSetupHandler] OpenSpec 初始化成功');
      return true;
    } catch (err) {
      this.updateOpenSpecStep(
        'openspecInit',
        SpecSetupStepStatus.Failed,
        {
          errorCode: SpecSetupErrorCode.OPENSPEC_INIT_FAILED,
          errorMessage: `初始化 OpenSpec 异常: ${getErrorMessage(err)}`,
        }
      );
      return false;
    }
  }

