  // ==================== Setup 执行流程 ====================

  /**
   * 执行 OpenSpec Setup 流程 (2 步)
   * 1. CLI 检测/安装 (包含 Node.js 前置检查)
   * 2. 目录初始化
   *
   * 版本选择逻辑：
   * - 如果 CLI 未安装：全局安装用户选择的版本
   * - 如果 CLI 已安装且版本匹配：使用全局命令
   * - 如果 CLI 已安装但版本不匹配：使用 npx 执行特定版本
   *
   * 只在状态真正变化时触发通知
   * @param version 请求的 OpenSpec 版本
   * @returns 是否全部成功
   */
  public async runOpenspecSetup(
    version: '0.23' | '1.x' = '0.23',
    upgradeCli = true
  ): Promise<boolean> {
    printLog(`[SpecSetupHandler] 开始 OpenSpec Setup (版本: ${version})...`);

    // 步骤 1: 检测 CLI (静默检测)
    const cliCheck = await this.checkOpenspecCli(true);

    // 如果 CLI 检测失败且状态是 Failed (Node.js 问题)，直接返回
    if (!cliCheck.installed && this.setupStatus.openspec.openspecCli.status === SpecSetupStepStatus.Failed) {
      this.notifyStatusChange();
      printLog('[SpecSetupHandler] OpenSpec Setup 失败: 前置条件不满足');
      return false;
    }

    let installedVersion: string | undefined = cliCheck.version;

    // 如果 CLI 未安装，尝试全局安装用户选择的版本
    if (!cliCheck.installed) {
      printLog(`[SpecSetupHandler] CLI 未安装，开始全局安装 ${version} 版本`);
      const installOk = await this.installOpenspecCli(version);
      if (!installOk) {
        printLog('[SpecSetupHandler] OpenSpec Setup 失败: CLI 安装失败');
        return false;
      }
      // 安装成功后，再次检测获取安装的版本号
      const recheckResult = await this.checkOpenspecCli(true);
      installedVersion = recheckResult.version;
    } else if (!isVersionMatch(installedVersion!, version)) {
      // CLI 已安装但版本不匹配
      if (upgradeCli) {
        printLog(`[SpecSetupHandler] 用户选择升级 CLI: ${installedVersion} -> ${version}`);
        const installOk = await this.installOpenspecCli(version);
        if (!installOk) {
          printLog('[SpecSetupHandler] OpenSpec Setup 失败: CLI 升级失败');
          return false;
        }
        const recheckResult = await this.checkOpenspecCli(true);
        installedVersion = recheckResult.version;
      } else {
        printLog(`[SpecSetupHandler] CLI 已安装 (${installedVersion})，但与请求版本 (${version}) 不匹配，将使用 npx 执行`);
      }
    } else {
      // CLI 已安装且版本匹配
      printLog(`[SpecSetupHandler] CLI 已安装 (${installedVersion})，版本匹配，将使用全局命令`);
    }

    // 步骤 2: 检测目录 (静默检测)
    const initDone = await this.checkOpenspecInit(true);
    if (!initDone) {
      const initOk = await this.initOpenspec(version, installedVersion);
      if (!initOk) {
        printLog('[SpecSetupHandler] OpenSpec Setup 失败: 初始化失败');
        return false;
      }
    }

    // 全部完成，触发最终通知
    this.notifyStatusChange();
    printLog('[SpecSetupHandler] OpenSpec Setup 完成');
    return true;
  }

  /**
   * 执行 SpecKit Setup 流程 (2 步)
   * 1. CLI 检测/安装 (包含 uv 前置检查)
   * 2. 目录初始化
   *
   * 只在状态真正变化时触发通知
   * @returns 是否全部成功
   */
  public async runSpeckitSetup(): Promise<boolean> {
    printLog('[SpecSetupHandler] 开始 SpecKit Setup...');

    // 步骤 1: 检测 CLI (静默检测)
    const cliInstalled = await this.checkSpecifyCli(true);

    // 如果 CLI 检测失败且状态是 Failed (uv 问题)，直接返回
    if (!cliInstalled && this.setupStatus.speckit.specifyCli.status === SpecSetupStepStatus.Failed) {
      this.notifyStatusChange();
      printLog('[SpecSetupHandler] SpecKit Setup 失败: 前置条件不满足');
      return false;
    }

    // 如果 CLI 未安装，尝试安装
    if (!cliInstalled) {
      const installOk = await this.installSpecifyCli();
      if (!installOk) {
        printLog('[SpecSetupHandler] SpecKit Setup 失败: CLI 安装失败');
        return false;
      }
    }

    // 步骤 2: 检测目录 (静默检测)
    const initDone = await this.checkSpeckitInit(true);
    if (!initDone) {
      const initOk = await this.initSpeckit();
      if (!initOk) {
        printLog('[SpecSetupHandler] SpecKit Setup 失败: 初始化失败');
        return false;
      }
    }

    // 全部完成，触发最终通知
    this.notifyStatusChange();
    printLog('[SpecSetupHandler] SpecKit Setup 完成');
    return true;
  }

  /**
   * 检测是否为 0.23 版本（通过 AGENTS.md 文件判断）
   */
  private async checkIs023Version(): Promise<boolean> {
    try {
      const agentsUri = vscode.Uri.joinPath(
        vscode.Uri.file(this.workspaceRoot),
        'openspec',
        'AGENTS.md'
      );
      await vscode.workspace.fs.stat(agentsUri);
      return true;
    } catch {
      return false;
    }
  }

  /**
   * 升级 OpenSpec CLI 到 1.x
   * @returns 升级后的版本号，失败返回 null
   */
  private async upgradeOpenspecCli(): Promise<{
    ok: boolean;
    version?: string;
    errorMessage?: string;
  }> {
    const installResult = await runTerminalCommand(
      'npm install -g @fission-ai/openspec@^1',
      this.workspaceRoot,
      { timeout: 300000 }
    );

    if (!installResult.success) {
      printLog(`[SpecSetupHandler] CLI 升级失败: ${installResult.error}`);
      return { ok: false, errorMessage: `npm install 执行失败: ${installResult.error || '未知错误'}` };
    }

    const versionResult = await runTerminalCommand(
      'openspec --version',
      this.workspaceRoot,
      { timeout: 10000 }
    );

    if (!versionResult.success) {
      printLog(`[SpecSetupHandler] 无法验证升级后的版本: ${versionResult.error}`);
      return { ok: false, errorMessage: `CLI 安装成功但验证失败: ${versionResult.error || '命令不可用'}` };
    }

    const version = extractVersion(versionResult.output);
    if (!version) {
      return { ok: false, errorMessage: `版本号格式无法识别: ${versionResult.output}` };
    }
    return { ok: true, version };
  }

  /**
   * 执行文档迁移 (openspec init --tools none --force)
   */
  private async migrateOpenspecDocs(): Promise<boolean> {
    const result = await runTerminalCommand(
      'openspec init --tools none --force',
      this.workspaceRoot,
      { timeout: 60000 }
    );

    if (!result.success) {
      printLog(`[SpecSetupHandler] 文档迁移失败: ${result.error}`);
    }
    return result.success;
  }

  /**
   * 执行 OpenSpec 升级流程 (0.23 -> 1.x)
   *
   * 步骤：
   * 1. 检测是否为 0.23 版本
   * 2. 升级 CLI 到 1.x
   * 3. 执行文档迁移 (openspec update --force)
   *
   * @returns 升级后的版本号，失败则返回 null
   */
  public async runOpenspecUpgrade(): Promise<string | null> {
    printLog('[SpecSetupHandler] 开始 OpenSpec 升级流程 (0.23 -> 1.x)...');

    // 初始化升级状态
    this.setupStatus.openspecUpgrade = createDefaultUpgradeStatus();
    this.notifyStatusChange();

    // 步骤 1: 检测版本
    this.updateOpenSpecUpgradeStep('versionCheck', SpecSetupStepStatus.Running);
    const is023 = await this.checkIs023Version();
    if (!is023) {
      this.updateOpenSpecUpgradeStep('versionCheck', SpecSetupStepStatus.Failed, {
        errorCode: SpecSetupErrorCode.UPGRADE_NOT_023,
        errorMessage: '此项目不是 OpenSpec 0.23 版本，无需升级',
      });
      printLog('[SpecSetupHandler] 版本检测失败: 不是 0.23 版本');
      return null;
    }
    this.updateOpenSpecUpgradeStep('versionCheck', SpecSetupStepStatus.Completed);
    printLog('[SpecSetupHandler] 版本检测成功: 确认为 0.23 版本');

    // 步骤 2: 升级 CLI
    this.updateOpenSpecUpgradeStep('cliUpgrade', SpecSetupStepStatus.Running);
    printLog('[SpecSetupHandler] 开始升级 OpenSpec CLI 到 1.x...');
    const cliResult = await this.upgradeOpenspecCli();
    if (!cliResult.ok) {
      this.updateOpenSpecUpgradeStep('cliUpgrade', SpecSetupStepStatus.Failed, {
        errorCode: SpecSetupErrorCode.UPGRADE_CLI_FAILED,
        errorMessage: cliResult.errorMessage!,
      });
      return null;
    }
    this.setupStatus.openspecUpgrade!.upgradedVersion = cliResult.version!;
    this.updateOpenSpecUpgradeStep('cliUpgrade', SpecSetupStepStatus.Completed);
    printLog(`[SpecSetupHandler] CLI 升级成功: ${cliResult.version}`);

    // 步骤 3: 迁移文档
    this.updateOpenSpecUpgradeStep('migrateDocs', SpecSetupStepStatus.Running);
    printLog('[SpecSetupHandler] 开始执行文档迁移...');
    const migrateOk = await this.migrateOpenspecDocs();
    if (!migrateOk) {
      this.updateOpenSpecUpgradeStep('migrateDocs', SpecSetupStepStatus.Failed, {
        errorCode: SpecSetupErrorCode.UPGRADE_MIGRATE_FAILED,
        errorMessage: '文档迁移失败',
      });
      return null;
    }
    this.updateOpenSpecUpgradeStep('migrateDocs', SpecSetupStepStatus.Completed);
    printLog('[SpecSetupHandler] 文档迁移成功');

    printLog(`[SpecSetupHandler] OpenSpec 升级完成: ${cliResult.version}`);
    return cliResult.version!;
  }
}

