import * as vscode from 'vscode';
import * as path from 'path';
import { createWorkspaceFile, getWorkspaceAbsolutePath, removeWorkspaceFile } from '../utils/file';
import { printLog } from '../handlers/logHandler/logHandler';
import getErrorMessage from '../utils/getErrorMessage';
import { FileType } from 'vscode';
import { getLanguageIdByFileName } from '@/utils/getLanguageId';
import delay from 'delay';
import * as os from 'os';
import * as fs from 'fs';
import { getReporter } from '@/utils/report';
import * as iconv from 'iconv-lite';
import { getWorkspaceEncoding } from '@/utils/getWorkspaceInfo';
import { updateDocumentContent } from '@/utils/document';

export interface ApplyItem {
  toolCallId: string;
  filePath: string;
  finalResult: string;
  isCreateFile?: boolean;
  beforeEdit: string;
}

export interface ApplyFile {
  filePath: string;
  finalResult: string;
  isCreateFile?: boolean;
  originalContent: string;
}


interface DiffFile {
  filePath: string;
  originalContent: string;
  finalResult: string;
  editor: vscode.TextEditor;
  isNewFile?: boolean;
  tempFilePath?: string; // 添加临时文件路径字段
}

export class EditApplyProvider {
  private diffFiles: Map<string, DiffFile> = new Map();
  private disposables: vscode.Disposable[] = [];
  private previewEditor: vscode.TextEditor | null = null;

  constructor() {
    this.disposables.push(
      vscode.window.onDidChangeVisibleTextEditors((editors) => {
        if (!this.diffFiles.size) return;
        for (const [filePath, diffFile] of this.diffFiles) {
          if (!editors.includes(diffFile.editor)) {
            // 清理临时文件
            this.cleanupTempFile(diffFile);
            this.diffFiles.delete(filePath);
          }
        }
      })
    );
  }

  private static get isSlientApply() {
    const config = vscode.workspace.getConfiguration('CodeMaker')
    return config.get<boolean>('BackendApplyCode', false)
  }

  /**
   * 清理临时文件
   */
  private cleanupTempFile(diffFile: DiffFile): void {
    if (diffFile.tempFilePath) {
      try {
        fs.unlinkSync(diffFile.tempFilePath);
        printLog(`清理临时文件: ${diffFile.tempFilePath}`);
      } catch (err) {
        // 忽略删除错误
        printLog(`清理临时文件失败: ${diffFile.tempFilePath}, ${getErrorMessage(err)}`);
      }
    }
  }

  /**
   * 生成唯一的临时文件名
   */
  private generateTempFileName(filePath: string): string {
    const fileName = path.basename(filePath);
    const parsedPath = path.parse(fileName);

    // 使用文件路径的hash来生成唯一后缀
    const pathHash = this.hashString(filePath);

    return `${parsedPath.name}-before-${pathHash}${parsedPath.ext}`;
  }

  /**
   * 更新文件内容
   */
  private async updateFileContent(currentDocument: vscode.TextDocument, content: string): Promise<void> {
    if (EditApplyProvider.isSlientApply) {
      currentDocument.encoding
      const contentBytes = iconv.encode(content, currentDocument.encoding || getWorkspaceEncoding());
      fs.writeFileSync(currentDocument.uri.fsPath, contentBytes);
    } else {
      await updateDocumentContent(currentDocument, content);
    }
  }

  /**
   * 简单的字符串hash函数
   */
  private hashString(str: string): string {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32bit integer
    }
    return Math.abs(hash).toString(36);
  }

  async previewDiffEdit(options: {
    filePath: string;
    beforeEdit: string;
    finalResult: string;
    isCreateFile?: boolean;
  }): Promise<{
    success: boolean;
    message?: string;
  }> {
    const {
      filePath,
      beforeEdit,
      finalResult,
      isCreateFile
    } = options;
    try {
      await this.closeAllDiffEditor();
      const fileName = path.basename(filePath);
      let targetDocument: vscode.TextDocument;
      let targetLanguage: string;
      let codeAfter = finalResult;

      if (isCreateFile) {
        targetLanguage = getLanguageIdByFileName(fileName);
        targetDocument = await vscode.workspace.openTextDocument({
          language: targetLanguage,
          content: '',
        })
      } else {
        targetDocument = await vscode.workspace.openTextDocument(getWorkspaceAbsolutePath(filePath));
        targetLanguage = targetDocument.languageId;
        const currentContent = targetDocument.getText();
        if (targetDocument.isDirty) {
          return {
            success: false,
            message: '文件有未保存改动，请先保存并进行 reapply'
          }
        } else if (currentContent.replace(/\r\n/g, '\n') !== beforeEdit.replace(/\r\n/g, '\n')) {
          return {
            success: false,
            message: '文件内容有变动，请尝试 reapply'
          }
        }
      }

      const afterDoc = await vscode.workspace.openTextDocument({
        language: targetLanguage,
        content: codeAfter,
      });

      // 打开 diff 编辑器
      await vscode.commands.executeCommand('vscode.diff',
        targetDocument.uri,
        afterDoc.uri,
        `Diff - ${filePath}`,
        { preview: true, viewColumn: vscode.ViewColumn.Active }
      )

      const editor = vscode.window.activeTextEditor;
      if (editor) {
        this.previewEditor = editor;
      }

      const diffFile: DiffFile = {
        filePath: filePath,
        originalContent: beforeEdit,
        finalResult: finalResult,
        editor: editor as vscode.TextEditor
      };
      this.diffFiles.set(filePath, diffFile);
      return {
        success: true
      };
    } catch (err) {
      return {
        success: false,
        message: getErrorMessage(err)
      };
    }
  }

  async previewDiffFile(options: {
    filePath: string;
    beforeEdit: string;
    finalResult: string;
    isCreateFile?: boolean;
  }): Promise<{
    success: boolean;
    message?: string;
  }> {
    const {
      filePath,
      beforeEdit,
      finalResult,
      isCreateFile
    } = options;
    try {
      await this.closeAllDiffEditor();
      let codeBefore: string = beforeEdit;

      // 创建临时文件，使用唯一的文件名
      const tempDir = os.tmpdir();
      const tempFileName = this.generateTempFileName(filePath);
      const tempFilePath = path.join(tempDir, tempFileName);

      const contentBytes = iconv.encode(codeBefore, getWorkspaceEncoding());
      fs.writeFileSync(tempFilePath, contentBytes);
      const tempUri = vscode.Uri.file(tempFilePath);

      const currentFileUri = vscode.Uri.file(getWorkspaceAbsolutePath(filePath));

      // 打开diff视图
      await vscode.commands.executeCommand(
        'vscode.diff',
        tempUri,
        currentFileUri,
        `Diff - ${filePath}`,
        { preview: true, viewColumn: vscode.ViewColumn.Active }
      );

      const editor = vscode.window.activeTextEditor;
      if (editor) {
        this.previewEditor = editor;
      }

      const diffFile: DiffFile = {
        filePath: filePath,
        originalContent: codeBefore,
        finalResult: finalResult,
        editor: editor as vscode.TextEditor,
        tempFilePath: tempFilePath // 保存临时文件路径
      };
      this.diffFiles.set(filePath, diffFile);
      return {
        success: true
      };
    } catch (err) {
      return {
        success: false,
        message: getErrorMessage(err)
      };
    }
  }

  checkDiffExist(filePath: string) {
    return this.diffFiles.has(filePath);
  }

  private async closeDiffEditor(diffFile: DiffFile): Promise<void> {
    const tabGroups = vscode.window.tabGroups.all;
    for (const tabGroup of tabGroups) {
      const tabs = tabGroup.tabs;
      for (const tab of tabs) {
        if (tab.label === `Diff - ${diffFile.filePath}`) {
          const editor = diffFile.editor;
          const edit = new vscode.WorkspaceEdit();
          if (editor.document.uri.scheme === 'untitled') {
            edit.replace(
              editor.document.uri,
              new vscode.Range(0, 0, editor.document.lineCount, 0),
              ''
            );
            await vscode.workspace.applyEdit(edit);
          }
          await vscode.window.tabGroups.close(tab);
          break;
        }
      }
    }

    // 清理临时文件
    this.cleanupTempFile(diffFile);
  }

  async closeAllDiffEditor(): Promise<void> {
    const tabGroups = vscode.window.tabGroups.all;
    for (const tabGroup of tabGroups) {
      const tabs = tabGroup.tabs;
      for (const tab of tabs) {
        if (tab.label.includes('cm-diff-preview')) {
          if (this.previewEditor) {
            const edit = new vscode.WorkspaceEdit();
            edit.replace(
              this.previewEditor.document.uri,
              new vscode.Range(0, 0, this.previewEditor.document.lineCount, 0),
              ''
            )
            this.previewEditor = null;
            await vscode.workspace.applyEdit(edit);
          }
          await vscode.window.tabGroups.close(tab);
        }
      }
    }
  }

  async acceptSingleEdit(applyItem: ApplyItem, force?: boolean) {
    const {
      filePath,
      finalResult,
      isCreateFile,
      beforeEdit,
      toolCallId
    } = applyItem;
    try {
      const diffFile = this.diffFiles.get(filePath);
      let absolutePath;
      let afterEdit;
      let currentDocument;
      if (diffFile) {
        absolutePath = getWorkspaceAbsolutePath(diffFile.filePath);
      } else {
        absolutePath = getWorkspaceAbsolutePath(filePath);
      }

      // 先确认文件是否存在
      let fileExist = false;
      try {
        const stat = await vscode.workspace.fs.stat(vscode.Uri.file(absolutePath));
        if (stat.type === FileType.File) {
          fileExist = true
        } else {
          fileExist = false;
        }
      } catch {
        fileExist = false;
      }

      if (diffFile) {
        const editor = diffFile.editor;
        afterEdit = editor.document.getText();
      } else {
        afterEdit = finalResult;
      }

      if (isCreateFile && !fileExist) {
        const fileUri = await createWorkspaceFile(absolutePath, '');
        currentDocument = await vscode.workspace.openTextDocument(fileUri);
      } else {
        currentDocument = await vscode.workspace.openTextDocument(absolutePath);
        if (currentDocument.isDirty) {
          printLog(`apply: 文件有未保存改动，请先保存并进行 reapply, toolCallId: ${toolCallId}, filePath: ${filePath}`);
          return {
            success: false,
            message: '文件有未保存改动，请先保存并进行 reapply'
          }
        }
      }

      if (currentDocument) {
        // 判断文档是不是已经变化了
        const currentContent = currentDocument.getText();
        if (currentContent.replace(/\r\n/g, '\n') === afterEdit.replace(/\r\n/g, '\n') && fileExist) {

          if (diffFile) {
            // 记录当前是否在 diff 编辑器中
            const isDiffEditorActive = vscode.window.activeTextEditor === diffFile.editor;
            if (isDiffEditorActive && currentContent.replace(/\r\n/g, '\n') !== finalResult.replace(/\r\n/g, '\n')) {
              // 先关闭 diff 编辑器
              await this.closeDiffEditor(diffFile);
              this.diffFiles.delete(filePath);
              await this.updateFileContent(currentDocument, finalResult);
              await delay(100);
              await this.previewDiffFile({
                filePath,
                beforeEdit,
                finalResult: finalResult,
                isCreateFile: false
              });
            }
          }

          return {
            success: true
          }
        }
        if (currentContent.replace(/\s/g, '') !== beforeEdit.replace(/\s/g, '') && fileExist) {
          const reporter = getReporter();
          reporter.appendMessage({
            event: 'CodeChat.before_edit_not_match',
            message: `文档内容变化导致 accept 前置判断不一致`,
            extends: {
              currentContent: currentContent,
              beforeEdit: beforeEdit,
              tool_id: toolCallId
            },
          })
          if (!force) {
            printLog(`apply: 文件内容有变动，请尝试 reapply, toolCallId: ${toolCallId}, filePath: ${filePath}`);
            return {
              success: false,
              message: '文件内容有变动，请尝试 reapply'
            }
          }
        }
        // 加上延迟，是由于修改和创建文件都是异步完成，等待一段时间让IO操作按时序完成,保证document的内容能正常修改
        await delay(100)
        await this.updateFileContent(currentDocument, afterEdit)
        if (diffFile) {
          // 关闭 diff 编辑器
          await this.closeDiffEditor(diffFile);
          this.diffFiles.delete(filePath);
        }
        return {
          success: true
        }
      } else {
        printLog(`apply: 文件读取异常, toolCallId: ${toolCallId}, filePath: ${filePath}`);
        return {
          success: false,
          message: 'apply 文件读取异常'
        }
      }
    } catch (err) {
      printLog(`apply: 文件修改失败, toolCallId: ${toolCallId}, filePath: ${filePath} ${getErrorMessage(err)}`);
      return {
        success: false,
        message: 'apply 文件修改失败'
      }
    }
  }

  async revertSingleEdit(applyFile: ApplyFile) {
    const { filePath, originalContent, isCreateFile } = applyFile;

    try {
      const diffFile = this.diffFiles.get(filePath);
      let absolutePath;
      let afterEdit;
      let currentDocument;

      absolutePath = getWorkspaceAbsolutePath(filePath);
      // 先确认文件是否存在
      let fileExist = false;
      try {
        const stat = await vscode.workspace.fs.stat(vscode.Uri.file(absolutePath));
        if (stat.type === FileType.File) {
          fileExist = true;
        } else {
          fileExist = false;
        }
      } catch {
        fileExist = false;
      }

      afterEdit = originalContent;

      if (isCreateFile) {
        // 删除文件
        if (!fileExist) {
          return {
            success: true
          }
        } else {
          removeWorkspaceFile(absolutePath);
        }
      } else {
        if (!fileExist) {
          await createWorkspaceFile(absolutePath, '');
        }
        currentDocument = await vscode.workspace.openTextDocument(absolutePath);
        if (currentDocument) {
          // 如果无需修改，则直接返回
          const currentContent = currentDocument.getText();
          if (currentContent.replace(/\r\n/g, '\n') === afterEdit.replace(/\r\n/g, '\n')) {
            return {
              success: true
            }
          }
        }
        await this.updateFileContent(currentDocument, afterEdit);
      }
      if (diffFile) {
        // 关闭 diff 编辑器
        await this.closeDiffEditor(diffFile);
        this.diffFiles.delete(filePath);
      }

      return {
        success: true
      };
    } catch (err) {
      printLog(`回退文件改动失败，${getErrorMessage(err)}`);
      return {
        success: false,
        message: '回退文件改动失败'
      };
    }
  }

  dispose(): void {
    // 清理所有临时文件
    for (const [filePath, diffFile] of this.diffFiles) {
      this.cleanupTempFile(diffFile);
    }

    this.disposables.forEach(d => d.dispose());
    this.diffFiles.clear();
  }
}

let editApplyProvider: EditApplyProvider | null = null;

export function initEditApplyProvider(context: vscode.ExtensionContext) {
  if (!editApplyProvider) {
    editApplyProvider = new EditApplyProvider();
  }
}

export function getEditApplyProvider() {
  if (!editApplyProvider) {
    editApplyProvider = new EditApplyProvider();
  }
  return editApplyProvider;
}

