  implements vscode.WebviewViewProvider {
  private leftOverMessages: any[] = [];
  private panelLeftOverMessages: any[] = [];
  public static readonly viewType = 'codeMaker.webView';

  private _view?: vscode.WebviewView;
  private extensionContext?: vscode.ExtensionContext;
  private requestController: AbortController | null = null;
  private hasInit: boolean = false;
  private scrollLine: number = 0;
  public _panel: vscode.WebviewPanel | null = null;
  private panelInit: boolean = false;
  private webviewEventEmitter = new vscode.EventEmitter<{ type: string; payload?: any }>();
  public readonly onWebviewEvent = this.webviewEventEmitter.event;
  private isReady = false;

  constructor(private context: vscode.ExtensionContext) {
    this.extensionContext = context;
  }

  public waitForWebviewEvent<T = unknown>(eventType: string, timeoutMs = 1800_000, signal?: AbortSignal): Promise<T> {
    if (eventType === 'app_init' && this.isReady) {
      return Promise.resolve(undefined as T);
    }
    return new Promise((resolve, reject) => {
      let finished = false;
      const disposables: vscode.Disposable[] = [];

      const cleanup = (error?: Error, value?: T) => {
        if (finished) return;
        finished = true;
        disposables.forEach((d) => d.dispose());
        if (error) reject(error);
        else resolve(value as T);
      };

      if (signal) {
        if (signal.aborted) {
          cleanup(new Error(`Event listener for ${eventType} was aborted`));
          return;
        }
        const abortHandler = () => {
          cleanup(new Error(`Event listener for ${eventType} was aborted`));
        };
        signal.addEventListener('abort', abortHandler);
        disposables.push({ dispose: () => signal.removeEventListener('abort', abortHandler) });
      }

      const disposable = this.onWebviewEvent(({ type, payload }) => {
        if (type === eventType) cleanup(undefined, payload as T);
      });
      disposables.push(disposable);

      const timeout = setTimeout(() => {
        cleanup(new Error(`Timed out waiting for event ${eventType}`));
      }, timeoutMs);
      disposables.push({ dispose: () => clearTimeout(timeout) });
    });
  }

  public replyToWebview(
    response: any,
    sourceWebview: vscode.Webview,
    sourcePanelId?: string
  ) {
    // 优先级：并行面板 > CM2面板 > 主会话
    if (sourcePanelId && sourcePanelId.startsWith('codebase-panel-')) {
      sourceWebview.postMessage({ ...response, targetPanelId: sourcePanelId });
    } else if (sourceWebview === this._panel?.webview) {
      sourceWebview.postMessage(response);
    } else if (sourceWebview === this._view?.webview) {
      sourceWebview.postMessage(response);
    } else {
      this.sendWebviewMessage(response);
    }
  }

  /**
   * 设置 Codebase Chat 面板的 loading 状态
   * @param panelId 面板 ID
   * @param loading 是否处于 loading 状态
   */
  private setPanelLoadingState(panelId: string | undefined, loading: boolean) {
    if (panelId && panelId.startsWith('codebase-panel-')) {
      if (CodebaseChatPanelManager.hasInstance()) {
        const panelManager = CodebaseChatPanelManager.getInstance();
        panelManager.setPanelLoading(panelId, loading);
      }
    }
  }

  /**
   * 设置 Codebase Chat 面板的标题（会话名称）
   * @param panelId 面板 ID
   * @param title 标题（会话名称）
   */
  private setPanelTitle(panelId: string | undefined, title: string) {
    if (panelId && panelId.startsWith('codebase-panel-')) {
      if (CodebaseChatPanelManager.hasInstance()) {
        const panelManager = CodebaseChatPanelManager.getInstance();
        panelManager.setPanelTitle(panelId, title);
      }
    }
  }

  public async handleMessage(message: any, webviewView: vscode.Webview) {
    const codeSearchManager = CodeSearchManager.getInstance(webviewView);
    const catchEdit = ActiveTextEditorCache.getInstance().getCachedEditor();
    switch (message.type) {
      case 'WEBVIEW_ACK': {
        const { event, payload } = message.data ?? {};
        if (typeof event === 'string') {
          this.webviewEventEmitter.fire({ type: event, payload });
        }
        if (message.data?.event === 'app_init') {
          this.isReady = true;
        }
        break;
      }
      case 'COPY_TO_CLIPBOARD': {
        vscode.env.clipboard.writeText(message.data);
        break;
      }
      case 'INSERT_WITH_DIFF': {
        // 将代码插入到编辑器中
        // 判断是否有激活中的editor，如果没有的话激活一个
        const editor = vscode.window.activeTextEditor || catchEdit;
        if (!editor) {
          webviewView.postMessage({
            type: 'actionInfo',
            data: {
              tab: 'chat',
              content: '请先打开一个文件',
            },
          });
          return;
        }
        // 获取当前光标选中行的开始和结束位置
        const selection = new vscode.Selection(
          editor.selection.start.line,
          0,
          editor.selection.end.line,
          editor.document.lineAt(editor.selection.end.line).text.length
        );
        // 获取当前光标选中行的文本
        const selectText = editor.document.getText(selection);
        // 获取选中区域的开始位置
        const start = selection.start;
        // 获取选中区域的结束位置
        const end = selection.end;
        // 将选中行的文本替换为生成的代码
        if (selectText && selectText.trim().length > 0) {
          editor.edit((editBuilder) => {
            editBuilder.replace(
              new vscode.Range(start, end),
              generateConflictText(selectText, message.data)
            );
          });
        } else {
          editor.edit((editBuilder) => {
            editBuilder.replace(new vscode.Range(start, end), message.data);
          });
        }
        break;
      }
      case 'INSERT_TO_EDITOR': {
        // 将代码插入到编辑器中
        // 判断是否有激活中的editor，如果没有的话激活一个
        const editor = vscode.window.activeTextEditor || catchEdit;
        if (!editor) {
          webviewView.postMessage({
            type: 'actionInfo',
            data: {
              tab: 'chat',
              content: `请先打开一个文件`,
            },
          });
          return;
        }
        // 获取当前光标选中行的开始和结束位置
        const selection = new vscode.Selection(
          editor.selection.start.line,
          0,
          editor.selection.end.line,
          editor.document.lineAt(editor.selection.end.line).text.length
        );
        // 获取选中区域的开始位置
        const start = selection.start;
        // 获取选中区域的结束位置
        const end = selection.end;
        // 将选中区域替换为新的文本
        editor.edit((editBuilder) => {
          editBuilder.replace(new vscode.Range(start, end), message.data);
        });
        break;
      }
      case 'initExtensionData': {
        const code_generate_model =
          this.context.globalState.get('code_generate_model') || '';
        const gateway_name = this.context.globalState.get('gateway_name') || '';
        this.sendWebviewMessage(
          {
            type: 'setExtensionData',
            data: {
              code_generate_model: code_generate_model,
              gateway_name: gateway_name,
            },
          },
          { targetType: 'all' }
        );

        break;
      }
      case 'INIT_REVIEW_DATA': {
        const editor = vscode.window.activeTextEditor;
        // code review初始化逻辑
        const workspaceReviewInfo: {
          [propName: string]: WorkspaceReviewInfo;
        } = this.context.globalState.get('codeReviewInfo') || {};
        const currentWorkspace = vscode.workspace.name as string;
        workspaceReviewInfo[currentWorkspace] = workspaceReviewInfo[
          currentWorkspace
        ] || {
          workspaceName: currentWorkspace,
          filesInfo: [],
        };
        const currentWorkspaceInfo = workspaceReviewInfo[currentWorkspace];
        this.sendWebviewMessage({
          type: 'sendReviewData',
          data: {
            filePath: editor
              ? vscode.workspace.asRelativePath(editor.document.uri)
              : undefined,
            fileList: currentWorkspaceInfo.filesInfo,
          },
        });

        break;
      }
      case 'OPEN_LOCAL_REVIEW_FILE': {
        const { filePath, lineNumber } = message.data;

        // 先尝试直接使用传入的路径
        let files = await vscode.workspace.findFiles(filePath);
        printLog(`[Local Review] Open File: ${filePath} (${files?.length} files found)`);

        // 如果找不到，再尝试计算路径
        if (!files || files.length === 0) {
          const computedFilePath = getRelativePathToWorkspace(filePath) || '';
          files = await vscode.workspace.findFiles(computedFilePath);
          printLog(`[Local Review] Open File (fallback): ${filePath} -> ${computedFilePath} (${files?.length} files found)`);
        }

        const fileUri = files && files[0];
        if (fileUri) {
          // await vscode.workspace.openTextDocument(fileUri);
          vscode.window
            .showTextDocument(fileUri, {
              viewColumn: vscode.ViewColumn.One,
              preserveFocus: false,
            })
            .then((editor: vscode.TextEditor) => {
              if (lineNumber >= editor.document.lineCount) {
                vscode.window.showErrorMessage(
                  `当前Review信息已失效，无法定位到代码行`
                );
                return;
              }
              const range = new vscode.Range(
                lineNumber,
                0,
                lineNumber,
                editor.document.lineAt(lineNumber).text.length
              );
              editor.selection = new vscode.Selection(range.start, range.end);
              // 滚动到指定范围
              editor.revealRange(range, vscode.TextEditorRevealType.InCenter);
            });
        } else {
          vscode.window.showErrorMessage(
            `当前Review信息已失效，无法定位到代码行`
          );
        }
        break;
        // if (fileExists) {
        // 	const visibleEditors = vscode.window.visibleTextEditors;
        // 	for (const editor of visibleEditors) {
        // 		if (editor.document.uri.fsPath === filePath) {
        // 			// 文件已经打开，激活编辑器窗口
        // 			vscode.window.showTextDocument(editor.document, editor.viewColumn);
        // 			return;
        // 		}
        // 	}
        // 	// 文件未打开，打开该文件
        // 	vscode.window.showTextDocument(fileUri);
        // }
      }
      case 'REQUEST_CODE_SEARCH': {
        const sourcePanelId = this.inferPanelIdFromSource(message);

        this.sendMessageWithRouting({
          type: 'actionMessageClear',
          targetPanelId: sourcePanelId,
        }, sourcePanelId);

        // 先判断是否登录，如果未登录的话，提示用户登录
        const isLogin = this.context.globalState.get('isLogin');
        updateStatusBarColor();
        if (!isLogin) {
          this.sendMessageWithRouting({
            type: 'receiveSearchDataError',
            targetPanelId: sourcePanelId,
          }, sourcePanelId);

          this.sendMessageWithRouting({
            type: 'actionError',
            targetPanelId: sourcePanelId,
            data: {
              tab: 'search',
              content: `请先登录再使用插件功能，如有疑问，请加入popo用户群：${POPO_GROUP_NUM}`,
            },
          }, sourcePanelId);
          vscode.window
            .showInformationMessage('CodeMaker：Please login first', 'Login')
            .then((value) => {
              if (value === 'Login') {
                login();
              }
            });
          return;
        }
        const data = message.data;
        let codeReviewUrl =
          this.extensionContext?.globalState.get('codeReviewUrl');
        let codeSearchUrl =
          this.extensionContext?.globalState.get('codeSearchUrl');
        let codeLintUrl = this.extensionContext?.globalState.get('codeLintUrl');
        let searchCancelToken = CancelToken.source();
        this.extensionContext?.globalState.update(
          'searchCancelToken',
          searchCancelToken
        );
        if (!codeReviewUrl || !codeSearchUrl || !codeLintUrl) {
          const extensionData = await getExtensionData(
            this.context,
            searchCancelToken
          ).catch((err) => {
            const errorMsg = getErrorMessage(err);
            this.sendMessageWithRouting({
              type: 'actionError',
              targetPanelId: sourcePanelId,
              data: {
                tab: 'search',
                content: errorMsg,
              },
            }, sourcePanelId);

            this.sendMessageWithRouting({
              type: 'receiveSearchDataError',
              targetPanelId: sourcePanelId,
            }, sourcePanelId);
          });
          if (!extensionData) return;
          const { code_review_proxy, code_search, code_lint_proxy } =
            extensionData || {};
          if (!code_search) {
            this.sendMessageWithRouting({
              type: 'actionError',
              targetPanelId: sourcePanelId,
              data: {
                tab: 'search',
                content:
                  'CodeSearch 使用需要接入代码仓库，如有需要联系 gzlinxiangxin 或添加用户群 (7896636) 咨询',
              },
            }, sourcePanelId);

            this.sendMessageWithRouting({
              type: 'receiveSearchDataError',
              targetPanelId: sourcePanelId,
            }, sourcePanelId);
            break;
          }
          codeReviewUrl = code_review_proxy;
          codeSearchUrl = code_search;
          codeLintUrl = code_lint_proxy;
          this.extensionContext?.globalState.update(
            'codeReviewUrl',
            codeReviewUrl
          );
          this.extensionContext?.globalState.update(
            'codeSearchUrl',
            codeSearchUrl
          );
          this.extensionContext?.globalState.update('codeLintUrl', codeLintUrl);
        }
        const traceId = generateTraceId();
        printLog('发送Code Search请求，traceId: ' + traceId);
        searchCancelToken = CancelToken.source();
        this.extensionContext?.globalState.update(
          'searchCancelToken',
          searchCancelToken
        );
        const username = this.extensionContext?.globalState.get('username');
        const codeSearchRes = await $post(
          codeSearchUrl as string,
          {
            ...data,
          },
          {
            requestName: 'Code Search',
            traceId,
            headers: {
              'X-Access-User': (username as string) || '',
              'X-Auth-Project': 'mhxy', // TODO：项目需要动态获取
              'X-Access-Project': 'mhxy',
            },
            timeout: 15 * 1000, // 15秒超时限制
          }
        ).catch((err) => {
          printLog(
            `Code Search出错，错误信息：${getErrorMessage(err) || '无'
            }，traceId: ${traceId}`
          );
          this.sendMessageWithRouting({
            type: 'actionError',
            targetPanelId: sourcePanelId,
            data: {
              tab: 'search',
              content: getErrorMessage(err),
            },
          }, sourcePanelId);

          this.sendMessageWithRouting({
            type: 'receiveSearchDataError',
            targetPanelId: sourcePanelId,
          }, sourcePanelId);
        });
        if (codeSearchRes?.items && !codeSearchRes?.items?.length) {
          this.sendMessageWithRouting({
            type: 'actionInfo',
            targetPanelId: sourcePanelId,
            data: {
              tab: 'search',
              content: '未搜索到相关代码',
            },
          }, sourcePanelId);
        }
        const items = codeSearchRes?.items || [];
        const searchId = codeSearchRes?.op_id || 'UNKNOWN';
        this.sendMessageWithRouting({
          type: 'receiveSearchData',
          targetPanelId: sourcePanelId,
          data: {
            items,
            id: searchId,
          },
        }, sourcePanelId);
        break;
      }
      case 'SEARCH_AND_OPEN': {
        const data = message.data;
        const { name, fileName, startLine } = data;
        const sourcePanelId = this.inferPanelIdFromSource(message);
        const matchFiles: any[] = [];
        const files = await vscode.workspace.findFiles(
          `**/${fileName}`,
          '**/{node_modules}/**'
        );
        const reqArr = (files || []).map((file: any) =>
          vscode.workspace.fs.readFile(vscode.Uri.file(file?.path))
        );
        const contents = await Promise.all(reqArr);
        contents.forEach((content, index) => {
          const contentStr = content.toString();
          if (contentStr.indexOf(startLine) > -1) {
            const lines = contentStr.split('\n');
            for (let i = 0; i < lines.length; i++) {
              if (lines[i]?.includes(startLine?.trim())) {
                matchFiles.push({
                  filePath: files[index]?.path,
                  lineIndex: i,
                  columnIndex: startLine.indexOf(name),
                });
                break;
              }
            }
          }
        });
        if (matchFiles.length) {
          const { filePath, lineIndex, columnIndex } = matchFiles[0] || {};
          vscode.workspace.openTextDocument(filePath).then((document) => {
            // 在编辑器中打开文件
            vscode.window.showTextDocument(document).then((editor) => {
              // 待滚动到的范围
              const position = new vscode.Position(
                lineIndex,
                columnIndex > -1 ? columnIndex : 0
              );
              const range = document.lineAt(lineIndex).range;
              editor.selection = new vscode.Selection(position, position);

              // 滚动到指定范围
              editor.revealRange(range, vscode.TextEditorRevealType.InCenter);
            });
          });
          this.sendMessageWithRouting({
            type: 'finishOpen',
            targetPanelId: sourcePanelId,
          }, sourcePanelId);
        } else {
          this.sendMessageWithRouting({
            type: 'finishOpen',
            targetPanelId: sourcePanelId,
          }, sourcePanelId);

          this.sendMessageWithRouting({
            type: 'actionInfo',
            targetPanelId: sourcePanelId,
            data: {
              tab: 'search',
              content: `本地未找到该代码文件，请先确保工作区有包含相关代码文件。PS：远端仓库文件浏览正在规划中。`,
            },
          }, sourcePanelId);
        }
        break;
      }
      case 'OPEN_FILE': {
        const data = message.data;
        const { filePath, code, startLine, endLine } = data;
        // OPTIMIZED: 通过 findFiles 的方式做目前看起来速度不太行，暂时取消，再优化下
        // let openFilePath = filePath;
        // const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
        // if (!path.isAbsolute(openFilePath) && workspaceFolder) {
        //   // openFilePath = path.join(workspaceFolder.uri.fsPath, filePath);
        //   const fileResults = await vscode.workspace.findFiles(`**/${filePath}`);
        //   const file = fileResults?.[0];
        //   if (file) {
        //     openFilePath = file.path;
        //     // windows 下可能路径前面会有斜杠，需要去掉
        //     if (openFilePath.startsWith('/')) {
        //       openFilePath = openFilePath.slice(1);
        //     }
        //   }
        // }
        let openFilePath = filePath;
        const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
        if (!path.isAbsolute(openFilePath) && workspaceFolder) {
          openFilePath = path.join(workspaceFolder.uri.fsPath, filePath);
        }
        try {
          if (existsSync(openFilePath)) {
            if (isImageFile(openFilePath)) {
              const uri = vscode.Uri.file(filePath);
              await vscode.commands.executeCommand('vscode.open', uri);
              return
            }
            const targetDocument = await vscode.workspace.openTextDocument(openFilePath);
            const targetEditor = await vscode.window.showTextDocument(targetDocument);
            // 优先使用传入的 startLine 和 endLine 进行定位选中
            if (typeof startLine === 'number' && startLine >= 0) {
              // startLine 和 endLine 为行号（从 0 或 1 开始，这里假设从 1 开始，需转为 0-based）
              const locateStart = startLine > 0 ? startLine - 1 : 0;
              const locateEnd = typeof endLine === 'number' && endLine >= startLine ? endLine - 1 : locateStart;
              // 确保行号不超出文档范围
              const maxLine = targetDocument.lineCount - 1;
              const safeStart = Math.min(locateStart, maxLine);
              const safeEnd = Math.min(locateEnd, maxLine);
              if (safeStart > safeEnd || safeStart === 0 && safeEnd === maxLine) return
              targetEditor.selection = new vscode.Selection(
                new vscode.Position(safeStart, 0),
                new vscode.Position(safeEnd, targetDocument.lineAt(safeEnd).text.length)
              );
              targetEditor.revealRange(targetEditor.selection, vscode.TextEditorRevealType.InCenter);
            } else if (code) {
              // 如果没有传入行号，则通过 code 内容进行匹配定位
              const codeLines = code.split('\n');
              let locateStart = findLineNumber(targetDocument, codeLines[0]);
              if (locateStart < 0) {
                // 第一行可能有模型添加的注释，容错找找第二行
                if (codeLines[1]) {
                  locateStart = findLineNumber(targetDocument, codeLines[1]);
                }
              }
              if (locateStart < 0) {
                locateStart = 0;
              }
              let locateEnd = findLineNumber(targetDocument, codeLines[codeLines.length - 1], locateStart);
              if (locateEnd < 0) {
                locateEnd = locateStart;
              }
              printLog(`[OPEN_FILE] openFilePath: ${openFilePath}, locateStart: ${locateStart}, locateEnd: ${locateEnd}`);
              if (targetEditor && locateStart > 0) {
                targetEditor.selection = new vscode.Selection(
                  new vscode.Position(locateStart, 0),
                  new vscode.Position(locateEnd, targetDocument?.lineAt(locateEnd)?.text?.length || 0)
                );
              } else {
                targetEditor.selection = new vscode.Selection(
                  new vscode.Position(0, 0),
                  new vscode.Position(0, 0)
                );
              }
              targetEditor.revealRange(targetEditor.selection, vscode.TextEditorRevealType.AtTop);
            }
          } else {
            vscode.window.showInformationMessage(`未找到该文件: ${openFilePath}`);
          }
        } catch (err) {
          vscode.window.showErrorMessage(`未能打开文件: ${openFilePath}`);
          printLog(`OPEN_FILE 出错，${getErrorMessage(err)}`);
        }
        break;
      }
      case 'stopCodeChat': {
        this.stopResponse();
        break;
      }
      case 'STOP_CODE_SEARCH': {
        const searchCancelToken: any =
          this.extensionContext?.globalState.get('searchCancelToken');
        searchCancelToken?.cancel('stop code search');
        break;
      }
      case 'STOP_CODE_REVIEW': {
        const reviewCancelToken: any =
          this.extensionContext?.globalState.get('reviewCancelToken');
        reviewCancelToken?.cancel?.('stop review search');
        const reviewCanceler: any =
          this.extensionContext?.globalState.get('reviewCanceler');
        reviewCanceler?.();
        webviewView.postMessage({
          type: 'codeReviewLoading',
          data: false,
        });
        break;
      }
      case 'REMOVE_REVIEW': {
        const { mode, id, file } = message.data || {};
        const workspaceReviewInfo: {
          [propName: string]: WorkspaceReviewInfo;
        } = this.extensionContext?.globalState.get('codeReviewInfo') || {};
        const currentWorkspace = vscode.workspace.name as string;
        const currentWorkspaceInfo = workspaceReviewInfo[currentWorkspace];
        const fileIndex = currentWorkspaceInfo.filesInfo?.findIndex(
          (cachefile: ReviewFile) => {
            return cachefile.path === file.path;
          }
        );
        if (fileIndex >= 0 && currentWorkspaceInfo.filesInfo?.[fileIndex]) {
          const records: ReviewRecord[] =
            currentWorkspaceInfo.filesInfo?.[fileIndex]?.[
            mode === 'bugsensor' ? 'lintRecords' : 'reviewRecords'
            ];
          const index = records?.findIndex(
            (item: ReviewRecord) => item.reviewTime === id
          );
          if (index >= 0) {
            records.splice(index, 1);
          }
          this.extensionContext?.globalState.update(
            'codeReviewInfo',
            workspaceReviewInfo
          );
          this.sendWebviewMessage({
            type: 'updateReviewInfo',
            data: {
              fileInfo: currentWorkspaceInfo.filesInfo,
              mode: mode,
            },
          });
        }
        break;
      }
      case 'OPEN_GLOBAL_KEYBINDINGS': {
        const { key } = message.data || {};
        vscode.commands.executeCommand(
          'workbench.action.openGlobalKeybindings',
          key || 'CodeMaker'
        );
        break;
      }
      case 'OPEN_EXTENSION_SETTING': {
        vscode.commands.executeCommand(
          'workbench.action.openSettings',
          'CodeMaker'
        );
        break;
      }
      case 'OPEN_CHECK_UPDATE': {
        if (this.extensionContext) {
          await checkForUpdate(this.extensionContext, false);
        }
        break;
      }
      case 'OPEN_EXTENSION_SETTING_AUTHORIZATION_PATH': {
        vscode.commands.executeCommand(
          'workbench.action.openSettings',
          'Codebase'
        );
        break;
      }
      case 'OPEN_CHAT_MODELS_SETTING': {
        vscode.commands.executeCommand(
          'workbench.action.openSettings',
          'codechatmodels'
        );
        break;
      }
      case 'ADD_AUTHORIZATION_PATH': {
        await vscode.commands.executeCommand(
          'workbench.action.openSettings',
          'Codebase'
        );

        const data = message.data;
        const { path = [] } = data;
        const configuration = await vscode.workspace.getConfiguration(
          'CodeMaker'
        );
        const authorizationPathConfig =
          (getCodeMakerConfig('CodebaseDefaultAuthorizationPath') as any) || [];

        await configuration.update(
          'CodebaseDefaultAuthorizationPath',
          [...authorizationPathConfig, ...path],
          true
        );
        break;
      }
      case 'UPDATE_CHAT_SUBMIT_KEY': {
        const data = message.data;
        const { submitKey } = data;

        const configuration = await vscode.workspace.getConfiguration(
          'CodeMaker'
        );

        await configuration.update(
          'ChatSubmitKey',
          submitKey,
          true
        );
        break;
      }
      case 'LOGIN': {
        console.log('panel', webviewView);
        login();
        break;
      }
      case 'GET_INIT_DATA': {
        const data = message.data;
        this.sendInitData(data && data.isExpired, webviewView);
        break;
      }
      case 'START_NETWORK_DIAGNOSTIC': {
        const { testTargets } = message.value || {};
        const sourcePanelId = this.inferPanelIdFromSource(message);
        const diagnostics = getNetworkDiagnostics();
        diagnostics
          .diagnose((progress) => {
            this.sendMessageWithRouting({
              type: 'NETWORK_DIAGNOSTIC_PROGRESS',
              targetPanelId: sourcePanelId,
              value: progress,
            }, sourcePanelId);
