          function mergeAndDeduplicateByCode(dataList: any[]) {
            const allItems = dataList.flatMap(data => data.items);
            const uniqueMap = new Map();

            allItems.forEach(item => {
              if (item.code) {
                // 如果已存在相同code的项目，优先保留 codemaker_public: true 的数据
                if (!uniqueMap.has(item.code) || item.codemaker_public) {
                  uniqueMap.set(item.code, item);
