        }

        // SVN 项目优先使用外链和 svn info 信息来查找
        if (task?.repoType === 'svn') {
          const branch = ['develop', 'dynamic'].includes(task?.scanMode) ? issue?.branch : '';
          const fullPath = getCompleteSvnUrl(task?.masterBanch, branch, filePath);
          if (fullPath) {
            printLog(`[CodeScan] 文件完整路径: ${fullPath}`);

            // 先检查外链
            const externalLink = findFileInExternalLink(fullPath);
            if (externalLink && existsSync(externalLink)) {
              printLog(`[CodeScan] 文件匹配到外链: ${externalLink}`);
              const matchLine = await compareIssueLine(externalLink, startLine, issue.lineHash, context.content, context.offset);
              printLog(`[CodeScan] 外链文件上下文匹配状态: ${!!matchLine}`);
              if (matchLine) {
                fileUri = vscode.Uri.file(externalLink);
                lineOffset = matchLine.offset;
              }
            }

            // 再检查 svn info 信息
            const svnLink = findFineInSvnLink(fullPath);
            if (svnLink && existsSync(svnLink)) {
              printLog(`[CodeScan] 在 SVN 仓库中找到文件: ${svnLink}`);
              const matchLine = await compareIssueLine(svnLink, startLine, issue.lineHash, context.content, context.offset);
              printLog(`[CodeScan] SVN 仓库文件上下文匹配状态: ${!!matchLine}`);
              if (matchLine) {
                fileUri = vscode.Uri.file(svnLink);
                lineOffset = matchLine.offset;
              }
            }
          }
        }

        // 兜底在本地目录查找
        if (!fileUri) {
          try {
            // 将根目录也作为一个子目录来处理
            const allDirs = ['', ...getWorkspaceDirIndex()];
            for (const dir of allDirs) {
              const fullPath = path.join(rootPath, dir, filePath);
              if (existsSync(fullPath)) {
                const matchLine = await compareIssueLine(fullPath, startLine, issue.lineHash, context.content, context.offset);
                if (matchLine) {
                  fileUri = vscode.Uri.file(fullPath);
                  lineOffset = matchLine.offset;
                  printLog(`[CodeScan] 在 ${dir || '根'} 目录中找到文件: ${fullPath}`);
                  break;
                }
              }
            }
          } catch (error) {
            printLog(`[CodeScan] 查找文件失败: ${getErrorMessage(error)}`);
          }
        }

        printLog(
          `[CodeScan] 文件查找结果: 文件${fileUri ? '存在' : '不存在'}，耗时${(Date.now() - startTime) / 1000}S`
        );

        if (fileUri) {
          params.isInWorkspace = true;
          vscode.window
            .showTextDocument(fileUri, {
              viewColumn: vscode.ViewColumn.One,
              preserveFocus: false,
            })
            .then((editor: vscode.TextEditor) => {
              const range = new vscode.Range(
                startLine + lineOffset,
                startCharacter,
                endLine + lineOffset,
                endCharacter
              );
              editor.selection = new vscode.Selection(range.start, range.end);
              // 滚动到指定范围
              editor.revealRange(range, vscode.TextEditorRevealType.AtTop);
            })
            .then(() => {
              openCodeScanIssuePanel(
                this.extensionContext as vscode.ExtensionContext,
                params
              );
              this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_FINISH' });
            });
        } else {
          openCodeScanIssuePanel(
            this.extensionContext as vscode.ExtensionContext,
            params
          );
          this.sendWebviewMessage({ type: 'OPEN_CODESCAN_ISSUE_FINISH' });
        }
        break;
