          const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
          const workspacePath = workspaceFolder?.uri.fsPath;
          if (!workspacePath) {
            throw new Error('未找到工作区');
          }

          const currentBranchResult = await execCommand('git rev-parse --abbrev-ref HEAD', workspacePath);
          if (currentBranchResult.code === 0) {
            const currentBranch = currentBranchResult.stdout;
            if (currentBranch === branch) {
              vscode.window.showInformationMessage(`当前已经在 ${branch} 分支上`);
              return;
            }
          }

          // 执行 git fetch 获取最新分支
          const fetchResult = await vscode.window.withProgress(
            {
              location: vscode.ProgressLocation.Notification,
              title: '正在获取最新分支...',
              cancellable: false
            },
            () => execCommand('git fetch', workspacePath)
          );

          if (fetchResult.code !== 0) {
            throw new Error(`获取分支失败，错误信息：${fetchResult.stderr}`);
          }

          // 切换到目标分支
          const checkoutResult = await vscode.window.withProgress(
            {
              location: vscode.ProgressLocation.Notification,
              title: `正在切换到 ${branch} 分支...`,
              cancellable: false
            },
            () => execCommand(`git checkout ${branch}`, workspacePath)
          );

          if (checkoutResult.code !== 0) {
            throw new Error(`错误信息：${checkoutResult.stderr}`);
          }

          vscode.window.showInformationMessage(`已成功切换到 ${branch} 分支`);
        } catch (error) {
          const errorMessage = getErrorMessage(error);
          vscode.window.showErrorMessage(`切换分支失败，${errorMessage}`);
        }
        break;
