        const options: vscode.OpenDialogOptions = {
          canSelectFolders: true,
          canSelectFiles: false,
          canSelectMany: false,
          openLabel: '打开',
          title: '选择要打开的文件夹',
        };
        vscode.window.showOpenDialog(options).then(async (folderUri) => {
          if (folderUri && folderUri[0]) {
            const selectedPath = folderUri[0].fsPath;
            try {
              // 在当前窗口切换到选中的文件夹
              await vscode.commands.executeCommand(
                'vscode.openFolder',
                vscode.Uri.file(selectedPath),
                false // false 表示在当前窗口打开，true 表示在新窗口打开
              );
            } catch (error) {
              const errorMessage = getErrorMessage(error);
              vscode.window.showErrorMessage(`打开失败：${errorMessage}`);
              printLog(`打开失败：${errorMessage}`);
            }
          }
        });
        break;
      }
      case 'RELOAD_WINDOW': {
        printLog('[WebviewProvider] Reload Window');
        vscode.commands.executeCommand('codemaker.reload-window');
        break;
      }
    }
  }

