  public sendWebviewMessage(
    message: any,
    config?: {
      show?: boolean;
      // 是否全部发送，如果不是全部发送，优先发给 panel
      targetType?: 'all' | 'primary';
    }
  ) {
    const targetType = config?.targetType || this.getDefaultTargetType(message.type);
    if (targetType === 'all') {
      this.sendMessageToPanel(message);
      this.sendMessageToWebview(message);
      this.broadcastToCodebasePanels(message);
    } else {
      if (this._panel) {
        this.sendMessageToPanel(message);
      } else {
        if (config?.show) {
          this.showWebview();
        }
        this.sendMessageToWebview(message);
      }
    }
  }

  /**
   * 根据原始请求消息的来源，精确回复到发起请求的窗口
   * @param responseMessage 响应消息
   * @param originalMessage 原始请求消息（包含来源信息）
   */
  private sendTargetedMessage(responseMessage: any, originalMessage: any): void {
    const messageSource = originalMessage?._source;
    if (messageSource === 'newwindow' && this._panel && this.panelInit) {
      this._panel.webview.postMessage(responseMessage);
    } else if (messageSource === 'sidebar' && this._view && this.hasInit) {
      this._view.webview.postMessage(responseMessage);
    } else {
      // 如果无法确定来源或目标窗口不可用，则使用默认路由作为备用
      printLog(`[Webview] 消息来源: ${messageSource}, Panel可用: ${!!(this._panel && this.panelInit)}, Sidebar可用: ${!!(this._view && this.hasInit)}, 使用默认路由`);
      this.sendWebviewMessage(responseMessage);
    }
  }

  /**
   * 根据消息来源推断正确的 panelId
   * 这个方法解决了 CM2 新窗口消息没有明确 panelId 的问题
   */
  private inferPanelIdFromSource(message: any): string | undefined {
    let panelId = message.panelId;

    // 如果没有明确的 panelId，根据消息来源推断
    if (!panelId) {
      const messageSource = message._source;
      if (messageSource === 'newwindow') {
        panelId = 'newwindow-editor';
      } else if (messageSource === 'sidebar') {
        panelId = 'sidebar-main';
      }
    }

    return panelId;
  }

  /**
   * 统一消息路由方法 - 根据 panelId 路由到对应会话
   * 
   * 支持的 panelId 格式：
   *   - 'sidebar-main' 或 'sidebar-*': 主会话侧边栏
   *   - 'newwindow-editor' 或 'newwindow-*': CM2 新窗口面板
   *   - 'codebase-panel-*': 并行会话面板
   *   - undefined: 默认发送到侧边栏
   * 
   * @param message 要发送的消息
   * @param panelId 目标面板ID
   */
  public sendMessageWithRouting(message: any, panelId?: string): void {
    printLog(`[WebviewProvider] sendMessageWithRouting - panelId: ${panelId}, type: ${message.type}`);

    // 没有 panelId 时，默认发送到侧边栏
    if (!panelId) {
      printLog(`[WebviewProvider] No panelId, routing to sidebar (default), type: ${message.type}`);
      this.sendToSidebarPublic(message);
      return;
    }

    // 1. 主会话侧边栏
    if (panelId === 'sidebar-main' || panelId.startsWith('sidebar-')) {
      printLog(`[WebviewProvider] Routing to sidebar (panelId: ${panelId}), type: ${message.type}`);
      this.sendToSidebarPublic(message);
      return;
    }

    // 2. CM2 新窗口面板
    if (panelId === 'newwindow-editor' || panelId.startsWith('newwindow-')) {
      printLog(`[WebviewProvider] Routing to CM2 panel (panelId: ${panelId}), type: ${message.type}`);
      this.sendToPanelPublic(message);
      return;
    }

    // 3. 并行会话面板
    if (panelId.startsWith('codebase-panel-')) {
      import('../../utils/CodebaseChatPanelManager')
        .then(({ CodebaseChatPanelManager }) => {
          try {
            if (CodebaseChatPanelManager.hasInstance()) {
              const panelManager = CodebaseChatPanelManager.getInstance();
              if (panelManager.hasPanel(panelId)) {
                printLog(`[WebviewProvider] Routing to parallel panel: ${panelId}, type: ${message.type}`);
                panelManager.postToPanel(panelId, message);
              } else {
                printLog(`[WebviewProvider] Panel ${panelId} not found, fallback to sidebar`);
                this.sendToSidebarPublic(message);
              }
            } else {
              printLog(`[WebviewProvider] CodebaseChatPanelManager not initialized, fallback to sidebar`);
              this.sendToSidebarPublic(message);
            }
          } catch (error) {
            printLog(`[WebviewProvider] Message routing error: ${getErrorMessage(error)}, fallback to sidebar`);
            this.sendToSidebarPublic(message);
          }
        })
        .catch((error) => {
          printLog(`[WebviewProvider] Failed to load CodebaseChatPanelManager: ${getErrorMessage(error)}`);
          this.sendToSidebarPublic(message);
        });
      return;
    }

    // 4. 未知 panelId 格式，默认发送到侧边栏
    printLog(`[WebviewProvider] Unknown panelId format: ${panelId}, fallback to sidebar`);
    this.sendToSidebarPublic(message);
  }

  private broadcastToCodebasePanels(message: any) {
    try {
      import('../../utils/CodebaseChatPanelManager').then(({ CodebaseChatPanelManager }) => {
        // 只有在已初始化时才广播
        if (CodebaseChatPanelManager.hasInstance()) {
          const panelManager = CodebaseChatPanelManager.getInstance();
          panelManager.broadcastToAllPanels(message);
        }
      }).catch(() => {
        // 忽略导入错误
      });
    } catch {
      // 忽略错误
    }
  }

  private getDefaultTargetType(messageType: string): 'all' | 'primary' {
    // 初始化或者其他一些需要两边都发送的信息，统一在这里管理
    const systemMessages = [
      'setExtensionData', 'INIT_DATA', 'SYNC_WORKSPACE_INFO', 'sendReviewData', 'SYNC_WORKSPACE_LIST',
      'LOCAL_REVIEW_CONFIG', 'SYNC_MCP_SERVERS', 'EDITOR_FILE_STATE', 'WEBVIEW_BROADCAST',
      'APPLY_KEYBOARD_PASTE', 'ON_GET_WORKSPACE_PROBLEMS'
    ];
    return systemMessages.includes(messageType) ? 'all' : 'primary';
  }

