  public openWebviewPanel(viewColumn?: number) {
    // 如果已经打开了 panel ，那么就不能再打开一个新面板
    if (this._panel) return;
    this._panel = vscode.window.createWebviewPanel(
      'webviewPanel',
      'CODEMAKER',
      viewColumn || vscode.ViewColumn.One,
      {
        enableScripts: true,
        // 保留上下文，如果设置为 false 的话，切换 Tab 会导致 Panel 会被销毁
        retainContextWhenHidden: true,
      }
    );
    this.updatePanelState(this.context);

    // 在 CM2 面板创建后，确保发送初始化数据
    this.sendInitDataToNewPanel();
    const origin = WEBVIEW_URL;
    const hash = new Date().getTime();
    // CM2使用mode=newwindow + restoreSessionId=editor 进行存储区分
    const iframeUrl = `${WEBVIEW_URL}?hash=${hash || ''}&mode=newwindow&restoreSessionId=editor`;
    const codeServerUrl = (getCodeMakerConfig('CodeServerUrl') as string) || '';
