    }
    if (this._panel.webview) {
      this._panel.webview.html = `<!DOCTYPE html>
                                  <html lang="en">
                                    <head>
                                      <meta charset="UTF-8" />
                                      <meta name="viewport" content="width=device-width, initial-scale=1.0" />
                                      <title>CodeMaker</title>
                                      <style>::selection {background: transparent;}</style>
                                    </head>
                                    <body style="padding-left: 0; padding-right: 0" ondrop="handleDrop(event)" ondragenter="handleDragEnter(event)" ondragover="handleDragEnter(event)" ondragleave="handleDragLeave(event)" onDragEnd="handleDragLeave(event)">
                                      <iframe
                                        src="${iframeUrl}"
                                        frameborder="0"
                                        style="width: 100%; height: calc(100vh - 3px)"
                                        id="codemaker-webui-panel"
                                        allow="cross-origin-isolated; autoplay; clipboard-read; clipboard-write"
                                      ></iframe>
                                    </body>
                                    <script>
                                      const iframeuri = "${iframeUrl}";
                                      const iframe = document.getElementById('codemaker-webui-panel');
                                      const vscode = acquireVsCodeApi();
                                      window.addEventListener('message', event => {
                                        if (event.origin === "${origin}") {
                                          vscode.postMessage(event.data);
                                          console.log("[Event] From ${WEBVIEW_ID}", event.data);
                                          ${KEYBOARDS_SHORTCUTS_FIXED_CODE}
                                        } else if (
                                          event.origin && (
                                            event.origin.startsWith('vscode-webview') ${validOrigin
          ? '|| event.origin.includes("' + validOrigin + '")'
          : ''
        })
                                        ) {
                                          iframe.contentWindow.postMessage(event.data, iframeuri);
                                          console.log("[Event] To ${WEBVIEW_ID}", event.data);
                                        } else {
                                          console.log("[Event] Unknown in ${WEBVIEW_ID}", event);
                                        }
                                      });
                                    </script>
                                    <script>
                                      function handleDrop(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DROP', data: {
                                          files: e.dataTransfer.files,
                                          resourceUrlsData: e.dataTransfer.getData("resourceurls"),
                                        }}, iframeuri);
                                      }
                                      function handleDragEnter(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_ENTER'}, iframeuri);
                                      }
                                      function handleDragLeave(e) {
                                        e.preventDefault();
                                        iframe.contentWindow.postMessage({type: 'ON_WEBVIEW_DRAG_LEAVE'}, iframeuri);
                                      }
                                    </script>
                                  </html>`;

      // 监听来自新 Webview 面板的消息
      this._panel.webview.onDidReceiveMessage(
        async (message) => {
          // 收到消息可以认为 CM2 面板已完成渲染，清空 panelLeftOverMessages
          this.panelInit = true;
          if (this.panelLeftOverMessages && this.panelLeftOverMessages.length) {
            setTimeout(() => {
              for (const leftoverMessage of this.panelLeftOverMessages) {
                if (this._panel?.webview) {
                  this._panel.webview.postMessage(leftoverMessage);
                }
              }
              this.panelLeftOverMessages = [];
            }, 1000);
          }
          if (this?._panel?.webview) {
            // 为消息添加来源标识 - CM2 新窗口
            message._source = 'newwindow';
            void this.handleMessage(message, this._panel.webview);
          }
        },
        undefined,
        this.context.subscriptions
      );

      // 当 Webview 面板被关闭时进行清理
      this._panel.onDidDispose(
        () => {
          this._panel = null;
          this.context.workspaceState.update('webviewPanelState', null);
        },
        null,
        this.context.subscriptions
      );
      // 当面板位置发生变化的时候，需要更新缓存的位置信息
      this._panel.onDidChangeViewState(
        () => {
          this.updatePanelState(this.context);
        },
        null,
        this.context.subscriptions
      );
    }
  }

