  }

  /**
   * 向主会话侧边栏发送消息（公共方法）
   */
  public sendToSidebarPublic(message: any): void {
    if (this._view && this.hasInit) {
      this._view.webview.postMessage(message);
    } else {
      this.leftOverMessages.push(message);
    }
  }

  /**
   * 向新创建的 CM2 面板发送初始化数据
   * 这确保了新窗口能够获得与主会话相同的初始化数据
   */
  private sendInitDataToNewPanel(): void {
    // 延迟发送初始化数据，确保面板已经准备好接收消息
    setTimeout(() => {
      try {
        if (this._panel?.webview) {
          // 使用现有的 sendInitData 方法，传递 CM2 面板的 webview
          this.sendInitData(false, this._panel.webview);
          printLog('[WebviewProvider] 向 CM2 面板发送初始化数据');
        }
      } catch (error) {
        printLog(`[WebviewProvider] 发送 CM2 面板初始化数据失败: ${getErrorMessage(error)}`);
      }
    }, 500);
  }
}

let webviewProvider: CodeStreamWebviewProvider | null = null;

export function initWebviewProvider(context: vscode.ExtensionContext) {
  webviewProvider = new CodeStreamWebviewProvider(context);
  return webviewProvider;
}

export function getWebviewProvider() {
  if (webviewProvider) {
    return webviewProvider;
  }
}

