import * as vscode from 'vscode';
import { printLog } from "@/handlers/logHandler/logHandler";
import executeFunction from "@/utils/executeFunction";
import CodeStreamWebviewProvider from "..";

export default async function toolCall(options: {
  messageData: any;
  webviewProvider: CodeStreamWebviewProvider;
  webview: vscode.Webview;
  panelId?: string;
}) {
  const { messageData, webviewProvider, webview, panelId } = options;
  const { tool_name, tool_params, tool_id } = messageData;
  const sourcePanelId = panelId; // 保存请求来源的 panelId

  printLog(`TOOL_CALL: ${tool_name}, panelId: ${sourcePanelId}, params: ${JSON.stringify(tool_params).slice(0, 100)}`)
  const startTime = new Date().getTime();
  const result = await executeFunction({
    toolId: tool_id,
    toolName: tool_name,
    toolParams: tool_params,
    panelId: sourcePanelId,
  });
  const endTime = new Date().getTime();
  printLog(`TOOL_RESULT: ${tool_name}, cost_time: ${(endTime - startTime) / 1000}s result: ${result.content.slice(0, 200)}`);
  if (result && result.isError) {
    printLog(result.content);
  }

  const responseMessage = {
    type: 'TOOL_CALL_RESULT',
    targetPanelId: sourcePanelId,
    data: {
      tool_name: tool_name,
      tool_result: {
        path: result.path,
        content: result.content,
        isError: result.isError
      },
      extra: result.extra,
      tool_id: tool_id,
    },
  };

  // 使用统一的消息路由方法，根据 panelId 自动判断目标会话
  webviewProvider.sendMessageWithRouting(responseMessage, sourcePanelId);
}
